from flask import Flask, request, jsonify
from functools import wraps
import jwt
from typing import Callable

app = Flask(__name__)

def verify_jwt(algorithm: str):
    def decorator(f: Callable) -> Callable:
        @wraps(f)
        def wrapper(*args, **kwargs):
            token = request.headers.get('Authorization')
            if not token:
                return jsonify({'error': 'Missing JWT token'}), 401
            try:
                payload = jwt.decode(token.split()[1], app.config['SECRET_KEY'], algorithms=[algorithm])
                return f(payload, *args, **kwargs)
            except jwt.ExpiredSignatureError:
                return jsonify({'error': 'Token has expired'}), 401
            except jwt.InvalidTokenError:
                return jsonify({'error': 'Invalid token'}), 401
        return wrapper
    return decorator

@app.route('/internal', methods=['GET'])
@verify_jwt('HS256')
def internal_route(payload):
    return jsonify({'message': 'Internal route accessed', 'payload': payload})

@app.route('/public', methods=['GET'])
@verify_jwt('RS256')
def public_route(payload):
    return jsonify({'message': 'Public route accessed', 'payload': payload})

